entries.content:
@@preprocessing
<%_
// 防重复声明与变量获取
if (typeof userBackpack === 'undefined') var userBackpack = getvar('stat_data.主角.背包', { defaults: {} });
if (typeof currentLoc === 'undefined') var currentLoc = getvar('stat_data.世界.地点', { defaults: '' });

var hasGeneral = false;
var isClockTower = false;
var isFogCrystal = false;
var isMonastery = false;
var isSkyFall = false;
var isRoyal = false;

// 1. 扫描当前地点 (移除了法环，仅保留真正的教育区域)
if (currentLoc.includes('学院') || currentLoc.includes('大学') || currentLoc.includes('学园区') || currentLoc.includes('中环区')) hasGeneral = true;
if (currentLoc.includes('时钟塔')) isClockTower = true;
if (currentLoc.includes('汐潮学园区') || currentLoc.includes('学园区')) isFogCrystal = true;
if (currentLoc.includes('中环区') || currentLoc.includes('大修道院')) isMonastery = true;
if (currentLoc.includes('天陨学院')) isSkyFall = true;
if (currentLoc.includes('学院区') || currentLoc.includes('狮心战争学院') || currentLoc.includes('圣冠秘术学院') || currentLoc.includes('皇家翠玉工学院')) isRoyal = true;

// 2. 扫描背包标签
for (var itemName in userBackpack) {
    var item = userBackpack[itemName];
    if (item && Array.isArray(item.标签)) {
        if (item.标签.includes('学院凭证')) hasGeneral = true;
        if (item.标签.includes('秘银校徽')) isClockTower = true;
        if (item.标签.includes('幻色雾晶胸针')) isFogCrystal = true;
        if (item.标签.includes('祈光之羽胸针')) isMonastery = true;
        if (item.标签.includes('誓痕铁牌')) isSkyFall = true;
        if (item.标签.includes('鸢尾花纹章') || item.标签.includes('染血军籍牌') || item.标签.includes('黄铜刻度盘')) isRoyal = true;
    }
}
_%>

<%_ if (hasGeneral || isClockTower || isFogCrystal || isMonastery || isSkyFall || isRoyal) { _%>
触发指令：激活学院通用框架
<%_ } _%>

<%_ if (isClockTower) { _%>
触发指令：激活时钟塔特化
<%_ } _%>

<%_ if (isFogCrystal) { _%>
触发指令：激活雾晶学院特化
<%_ } _%>

<%_ if (isMonastery) { _%>
触发指令：激活大修道院特化
<%_ } _%>

<%_ if (isSkyFall) { _%>
触发指令：激活天陨学院特化
<%_ } _%>

<%_ if (isRoyal) { _%>
触发指令：激活艾瑟嘉德特化
<%_ } _%>
